    // ── orchestration.getLatestTurn ─────────────────────────────────────
    // The cloned MCode UI fetches the most recent turn for a thread via this
    // call. Verifies the dispatch resolves and the handler returns the real
    // TurnView with the highest `sequence` (turn_number) for the given thread.

    #[tokio::test]
    async fn test_orchestration_get_latest_turn_returns_highest_sequence() {
        let state = WsState::new_in_memory(16);

        // Seed a project + thread.
        let create_proj = serde_json::json!({
            "jsonrpc": "2.0", "id": 1, "method": "project/create",
            "params": { "name": "LT Project", "rootPath": "/tmp/lt" }
        });
        let resp = handle_rpc(&state, 1, &create_proj.to_string())
            .await
            .unwrap();
        let resp: JsonRpcResponse = serde_json::from_str(&resp).unwrap();
        let project_id = resp.result.unwrap()["id"].as_str().unwrap().to_string();

        let create_thread = serde_json::json!({
            "jsonrpc": "2.0", "id": 2, "method": "thread/create",
            "params": { "projectId": project_id, "providerId": "codex", "model": "gpt-5" }
        });
        let resp = handle_rpc(&state, 1, &create_thread.to_string())
            .await
            .unwrap();
        let resp: JsonRpcResponse = serde_json::from_str(&resp).unwrap();
        assert!(
            resp.error.is_none(),
            "thread/create failed: {:?}",
            resp.error
        );
        let thread_id = resp.result.unwrap()["id"].as_str().unwrap().to_string();

        // Start three turns with increasing sequences (1, 2, 3).
        for seq in 1..=3u64 {
            let req = serde_json::json!({
                "jsonrpc": "2.0", "id": 10 + seq, "method": "turn/start",
                "params": {
                    "threadId": thread_id,
                    "sequence": seq,
                    "userInput": format!("Question {}", seq)
                }
            });
            let resp = handle_rpc(&state, 1, &req.to_string()).await.unwrap();
            let resp: JsonRpcResponse = serde_json::from_str(&resp).unwrap();
            assert!(
                resp.error.is_none(),
                "turn/start seq={} failed: {:?}",
                seq,
                resp.error
            );
        }

        // getLatestTurn must return the turn with sequence 3 (highest).
        let req = serde_json::json!({
            "jsonrpc": "2.0", "id": 99, "method": "orchestration.getLatestTurn",
            "params": { "threadId": thread_id }
        });
        let resp = handle_rpc(&state, 1, &req.to_string()).await.unwrap();
        let resp: JsonRpcResponse = serde_json::from_str(&resp).unwrap();
        assert!(resp.error.is_none(), "{:?}", resp.error);
        let turn = resp.result.unwrap();
        // TurnView serializes snake_case (no serde rename_all on the struct).
        assert_eq!(turn["thread_id"], thread_id, "wrong thread");
        assert_eq!(turn["sequence"], 3, "expected highest sequence");
        assert_eq!(turn["user_input"], "Question 3");
        assert_eq!(turn["status"], "pending");
    }

    #[tokio::test]
    async fn test_orchestration_get_latest_turn_null_when_no_turns() {
        let state = WsState::new_in_memory(16);

        // Seed a project + thread but no turns.
        let create_proj = serde_json::json!({
            "jsonrpc": "2.0", "id": 1, "method": "project/create",
            "params": { "name": "Empty Project", "rootPath": "/tmp/empty" }
        });
        let resp = handle_rpc(&state, 1, &create_proj.to_string())
            .await
            .unwrap();
        let resp: JsonRpcResponse = serde_json::from_str(&resp).unwrap();
        let project_id = resp.result.unwrap()["id"].as_str().unwrap().to_string();

        let create_thread = serde_json::json!({
            "jsonrpc": "2.0", "id": 2, "method": "thread/create",
            "params": { "projectId": project_id, "providerId": "codex", "model": "gpt-5" }
        });
        let resp = handle_rpc(&state, 1, &create_thread.to_string())
            .await
            .unwrap();
        let resp: JsonRpcResponse = serde_json::from_str(&resp).unwrap();
        let thread_id = resp.result.unwrap()["id"].as_str().unwrap().to_string();

        // Thread has no turns → result must be null.
        let req = serde_json::json!({
            "jsonrpc": "2.0", "id": 5, "method": "orchestration.getLatestTurn",
            "params": { "threadId": thread_id }
        });
        let resp = handle_rpc(&state, 1, &req.to_string()).await.unwrap();
        let resp: JsonRpcResponse = serde_json::from_str(&resp).unwrap();
        assert!(resp.error.is_none(), "{:?}", resp.error);
        // No turns → result is null. `Option<Value>` round-trips JSON `null` as
        // `None` (serde deserializes null → None for Option), so accept either.
        assert!(
            resp.result.as_ref().is_none_or(|v| v.is_null()),
            "expected null result, got {:?}",
            resp.result
        );

        // A threadId with no matches at all (bogus id) also returns null.
        let req = serde_json::json!({
            "jsonrpc": "2.0", "id": 6, "method": "orchestration.getLatestTurn",
            "params": { "threadId": "does-not-exist" }
        });
        let resp = handle_rpc(&state, 1, &req.to_string()).await.unwrap();
        let resp: JsonRpcResponse = serde_json::from_str(&resp).unwrap();
        assert!(resp.error.is_none(), "{:?}", resp.error);
        assert!(
            resp.result.as_ref().is_none_or(|v| v.is_null()),
            "expected null result, got {:?}",
            resp.result
        );
    }

    #[tokio::test]
    async fn test_orchestration_replay_events_empty_store() {
        // An empty event repository has nothing to replay and no snapshots to
        // seed from, so the handler must return `{replayed:0, seeded:0}` and no
        // error. Exercises both dispatch aliases (dot + slash resolve to the
        // same handler).
        let state = WsState::new_in_memory(16);

        // Dot-string form (the raw MCode method the UI sends before remap).
        let req_dot = serde_json::json!({
            "jsonrpc": "2.0", "id": 1, "method": "orchestration.replayEvents"
        });
        let resp = handle_rpc(&state, 1, &req_dot.to_string()).await.unwrap();
        let resp: JsonRpcResponse = serde_json::from_str(&resp).unwrap();
        assert!(resp.error.is_none(), "{:?}", resp.error);
        let result = resp.result.unwrap();
        assert_eq!(result["replayed"].as_u64(), Some(0));
        assert_eq!(result["seeded"].as_u64(), Some(0));

        // Slash form (the served key the transport remaps to).
        let req_slash = serde_json::json!({
            "jsonrpc": "2.0", "id": 2, "method": "orchestration/replayEvents"
        });
        let resp = handle_rpc(&state, 1, &req_slash.to_string()).await.unwrap();
        let resp: JsonRpcResponse = serde_json::from_str(&resp).unwrap();
        assert!(resp.error.is_none(), "{:?}", resp.error);
        assert_eq!(resp.result.unwrap()["replayed"].as_u64(), Some(0));
    }

    #[tokio::test]
    async fn test_orchestration_replay_events_populated_store_returns_count() {
        // After creating a project (which appends a ProjectCreated event), the
        // replay must report a non-zero event count and surface the `{replayed,
        // seeded}` envelope shape. Resetting the read model first proves the
        // rebuild actually repopulates it.
        let state = WsState::new_in_memory(16);
        let create_proj = serde_json::json!({
            "jsonrpc": "2.0", "id": 1, "method": "project/create",
            "params": { "name": "Replay Project", "rootPath": "/tmp/replay" }
        });
        let resp = handle_rpc(&state, 1, &create_proj.to_string())
            .await
            .unwrap();
        let resp: JsonRpcResponse = serde_json::from_str(&resp).unwrap();
        assert!(resp.error.is_none(), "{:?}", resp.error);

        // Wipe the in-memory read model so the replay has something to rebuild.
        // `read_store` is the same `Arc<RwLock<ReadModelStore>>` the orchestrator
        // projects onto, so clearing it clears the orchestrator's read model.
        {
            let mut rm = state.read_store.write().await;
            *rm = syncode_orchestration::ReadModelStore::new();
        }
        let snap = state.read_store.read().await;
        assert_eq!(snap.projects.len(), 0, "read model should be cleared");
        drop(snap);

        // Replay — both the dot and slash keys must resolve to the handler.
        let req = serde_json::json!({
            "jsonrpc": "2.0", "id": 2, "method": "orchestration.replayEvents"
        });
        let resp = handle_rpc(&state, 1, &req.to_string()).await.unwrap();
        let resp: JsonRpcResponse = serde_json::from_str(&resp).unwrap();
        assert!(resp.error.is_none(), "{:?}", resp.error);
        let result = resp.result.unwrap();
        // At least one event (ProjectCreated) was replayed.
        let replayed = result["replayed"].as_u64().expect("replayed is u64");
        assert!(
            replayed > 0,
            "expected non-zero replayed count, got {replayed}"
        );
        // No snapshots were written by a bare create → seeded is 0.
        assert_eq!(result["seeded"].as_u64(), Some(0));

        // The read model was actually rebuilt — the project is back.
        let snap = state.read_store.read().await;
        assert_eq!(snap.projects.len(), 1);
        assert_eq!(
            snap.projects.values().next().unwrap().name,
            "Replay Project"
        );
    }

    #[tokio::test]
    async fn test_push_subscribe_records_subscription() {
        let state = WsState::new_in_memory(16);
        // Register connection 1 (subscribe requires a registered conn_id).
        let (tx, _rx) = tokio::sync::mpsc::unbounded_channel::<String>();
        state.register(1, tx).await;

        let req = serde_json::json!({
            "jsonrpc": "2.0", "id": 1, "method": "push/subscribe",
            "params": { "channel": "orchestration" }
        });
        let resp = handle_rpc(&state, 1, &req.to_string()).await.unwrap();
        let resp: JsonRpcResponse = serde_json::from_str(&resp).unwrap();
        assert!(resp.error.is_none(), "{:?}", resp.error);
        assert_eq!(resp.result.unwrap()["subscribed"], true);

        // The registry now records conn 1 subscribed to orchestration.
        let subs = state.subscriptions.read().await;
        assert!(
            subs.get_subscription(1)
                .unwrap()
                .is_subscribed("orchestration")
        );
        assert!(!subs.get_subscription(1).unwrap().is_subscribed("git"));
    }

