    // ─── GitHub-API ops RPC tests (T6c-14: gh-CLI-backed) ───────────────
    //
    // The pure parsing logic (`gh_parse::parse_github_remote`,
    // `gh_parse::parse_pr_view`) is unit-tested with canned fixtures below —
    // no `gh` subprocess required. The dispatch + listMethods tests verify
    // wiring without invoking `gh`. The two live-`gh` tests are
    // `#[ignore]`-gated (integration-only — they need a real GitHub repo +
    // network + `gh auth login`).

    /// `parse_github_remote` handles all four canonical remote-URL forms
    /// (git@ SSH, ssh://, https://, with/without trailing .git) and rejects
    /// non-GitHub hosts + malformed inputs.
    #[test]
    fn gh_parse_remote_url_forms() {
        use super::gh_parse::parse_github_remote;
        // SSH SCP-like form.
        assert_eq!(
            parse_github_remote("git@github.com:owner/repo.git"),
            Some(("owner".into(), "repo".into()))
        );
        // SSH SCP-like form without .git.
        assert_eq!(
            parse_github_remote("git@github.com:owner/repo"),
            Some(("owner".into(), "repo".into()))
        );
        // ssh:// form.
        assert_eq!(
            parse_github_remote("ssh://git@github.com/owner/repo.git"),
            Some(("owner".into(), "repo".into()))
        );
        // HTTPS form with .git.
        assert_eq!(
            parse_github_remote("https://github.com/owner/repo.git"),
            Some(("owner".into(), "repo".into()))
        );
        // HTTPS form without .git.
        assert_eq!(
            parse_github_remote("https://github.com/owner/repo"),
            Some(("owner".into(), "repo".into()))
        );
        // Whitespace is trimmed.
        assert_eq!(
            parse_github_remote("  https://github.com/owner/repo.git  "),
            Some(("owner".into(), "repo".into()))
        );

        // Non-GitHub hosts → None.
        assert_eq!(parse_github_remote("git@gitlab.com:owner/repo.git"), None);
        assert_eq!(
            parse_github_remote("https://bitbucket.org/owner/repo.git"),
            None
        );
        // Local path remote → None.
        assert_eq!(parse_github_remote("/home/user/repo"), None);
        // Malformed (too many segments) → None.
        assert_eq!(
            parse_github_remote("https://github.com/owner/repo/branches/main"),
            None
        );
        // Empty → None.
        assert_eq!(parse_github_remote(""), None);
        // Empty owner/repo segments → None.
        assert_eq!(parse_github_remote("https://github.com//repo"), None);
    }

    /// `parse_pr_view` maps the `gh pr view --json number,title,state,
    /// headRefName,baseRefName,url` output to the MCode
    /// `GitResolvedPullRequest` shape, normalizing `state` to lowercase +
    /// mapping unknown states to `"open"` defensively.
    #[test]
    fn gh_parse_pr_view_maps_to_mcode_shape() {
        use super::gh_parse::parse_pr_view;
        let fixture = serde_json::json!({
            "number": 42,
            "title": "feat: add gh-CLI ops",
            "state": "OPEN",
            "headRefName": "task/t6c14-github-gh-api",
            "baseRefName": "master",
            "url": "https://github.com/synara/syncode/pull/42",
        })
        .to_string();
        let pr = parse_pr_view(&fixture).expect("fixture must parse");
        assert_eq!(pr["number"], 42);
        assert_eq!(pr["title"], "feat: add gh-CLI ops");
        assert_eq!(pr["url"], "https://github.com/synara/syncode/pull/42");
        assert_eq!(pr["baseBranch"], "master");
        assert_eq!(pr["headBranch"], "task/t6c14-github-gh-api");
        assert_eq!(pr["state"], "open");

        // MERGED → "merged".
        let merged = serde_json::json!({
            "number": 7, "title": "t", "state": "MERGED",
            "headRefName": "h", "baseRefName": "b",
            "url": "https://github.com/o/r/pull/7",
        })
        .to_string();
        assert_eq!(parse_pr_view(&merged).unwrap()["state"], "merged");

        // Unknown state → defensive default "open".
        let weird = serde_json::json!({
            "number": 1, "title": "t", "state": "DRAFT",
            "headRefName": "h", "baseRefName": "b",
            "url": "https://github.com/o/r/pull/1",
        })
        .to_string();
        assert_eq!(parse_pr_view(&weird).unwrap()["state"], "open");

        // Missing `number` → Err.
        let bad = serde_json::json!({ "title": "t" }).to_string();
        assert!(parse_pr_view(&bad).is_err());

        // Malformed JSON → Err.
        assert!(parse_pr_view("not json").is_err());

        // Missing optional headRefName/baseRefName → empty string (not Err).
        let no_refs = serde_json::json!({
            "number": 1, "title": "t", "state": "open",
            "url": "https://github.com/o/r/pull/1",
        })
        .to_string();
        let pr = parse_pr_view(&no_refs).unwrap();
        assert_eq!(pr["headBranch"], "");
        assert_eq!(pr["baseBranch"], "");
    }

    /// `git.preparePullRequestThread` requires a `number` or `url` param —
    /// missing both is rejected with INVALID_PARAMS (param validation guard,
    /// exercised under BOTH dispatch forms so neither form slips past the
    /// guard into a panic). (GIT-3: the handler is now REAL — previously this
    /// asserted the `{ ok:false, reason }` stub envelope; with the real
    /// composition the first guard is the same param check as
    /// `git.resolvePullRequest`.)
    #[tokio::test]
    async fn git_prepare_pull_request_thread_requires_ref() {
        let state = WsState::new_in_memory(16);
        for method in [
            "git.preparePullRequestThread",
            "git/prepare-pull-request-thread",
        ] {
            let req = serde_json::json!({
                "jsonrpc": "2.0", "id": 1, "method": method, "params": {}
            });
            let resp = rpc(&state, 1, &req).await;
            assert!(
                resp.error.is_some(),
                "{method}: missing ref must be rejected with an error"
            );
            assert_eq!(
                resp.error.unwrap().code,
                crate::error_codes::INVALID_PARAMS,
                "{method}: missing ref must yield INVALID_PARAMS"
            );
        }
    }

    /// `git.preparePullRequestThread` (GIT-3) composes resolve + worktree. When
    /// `gh` cannot resolve the PR (no GitHub remote on the temp repo, or `gh`
    /// not installed), the handler must surface a graceful INTERNAL_ERROR —
    /// never a panic, never a stub envelope. The resolved-PR phase fails before
    /// the worktree phase runs, so no worktree is created. Verifies the
    /// graceful-degradation contract on a real temp git repo.
    #[tokio::test]
    async fn git_prepare_pull_request_thread_gh_failure_is_internal_error() {
        if !git_available() {
            eprintln!("skipping: git binary not on PATH");
            return;
        }
        // temp repo WITHOUT a GitHub origin → gh pr view cannot succeed.
        let repo = temp_git_repo();
        let state = WsState::new_in_memory(16);
        let req = serde_json::json!({
            "jsonrpc": "2.0", "id": 1, "method": "git.preparePullRequestThread",
            "params": {
                "cwd": repo.to_string_lossy(),
                "number": 1,
            }
        });
        let resp = rpc(&state, 1, &req).await;
        // gh failure is surfaced as a JSON-RPC INTERNAL_ERROR (NOT a stub
        // `{ ok:false }` envelope — the handler is REAL now).
        assert!(
            resp.error.is_some(),
            "gh failure must surface as a JSON-RPC error, got {:?}",
            resp.result
        );
        assert_eq!(
            resp.error.as_ref().unwrap().code,
            crate::error_codes::INTERNAL_ERROR,
            "gh failure must yield INTERNAL_ERROR"
        );
        // The error message must reference the resolve-PR phase (the first
        // composition step), confirming we reached the real handler and not a
        // stub short-circuit.
        let msg = resp.error.unwrap().message;
        assert!(
            msg.contains("resolve PR"),
            "error must come from the resolve-PR phase, got: {msg}"
        );
    }

    /// `git.preparePullRequestThread` (GIT-3) must resolve identically under
    /// BOTH dispatch forms (MCode dot-name + slash form) — the slash form is
    /// the wsNativeApi's variant, the dot-name is the tauriNativeApi's. Both
    /// must reach the same handler and produce the same outcome (here, the
    /// same INTERNAL_ERROR from gh on a no-remote temp repo). Guards against a
    /// dispatch-table regression that would silently 404 one form.
    #[tokio::test]
    async fn git_prepare_pull_request_thread_dispatches_both_forms() {
        if !git_available() {
            eprintln!("skipping: git binary not on PATH");
            return;
        }
        let repo = temp_git_repo();
        let state = WsState::new_in_memory(16);
        let mut codes: Vec<i32> = Vec::new();
        for method in [
            "git.preparePullRequestThread",
            "git/prepare-pull-request-thread",
            "git/preparePullRequestThread",
        ] {
            let req = serde_json::json!({
                "jsonrpc": "2.0", "id": 1, "method": method,
                "params": {
                    "cwd": repo.to_string_lossy(),
                    "number": 42,
                }
            });
            let resp = rpc(&state, 1, &req).await;
            // Every form must reach the handler (no MethodNotFound=-32601).
            let code = resp.error.as_ref().map(|e| e.code).unwrap_or(0);
            assert_ne!(
                code, -32601,
                "{method}: must not be MethodNotFound (dispatch table regression)"
            );
            codes.push(code);
        }
        // All three forms produce the same outcome (gh INTERNAL_ERROR on a
        // no-remote repo) — a dispatch-table mismatch would surface as
        // divergent codes.
        assert!(
            codes.iter().all(|&c| c == codes[0]),
            "all dispatch forms must yield the same code, got {codes:?}"
        );
    }

    /// `git.preparePullRequestThread` (GIT-3) — the composition result shape.
    /// When `gh` IS available AND authed AND the PR resolves, the handler must
    /// return the MCode `GitPreparePullRequestThreadResult` shape:
    /// `{ pullRequest: {...}, branch, worktreePath }`. We can't stage a real
    /// GitHub PR in CI, so this is a `#[ignore]`-gated integration test: run
    /// it manually against a real repo with an open PR (set
    /// `GIT_PREPARE_PR_TEST_REPO` to the repo path and
    /// `GIT_PREPARE_PR_TEST_NUMBER` to an open PR number). Verifies the full
    /// resolve→worktree composition end-to-end including the worktree directory
    /// existing on disk.
    #[tokio::test]
    #[ignore = "requires a real GitHub repo + open PR (set GIT_PREPARE_PR_TEST_REPO + GIT_PREPARE_PR_TEST_NUMBER)"]
    async fn git_prepare_pull_request_thread_real_pr_composition() {
        let Some(repo) = std::env::var_os("GIT_PREPARE_PR_TEST_REPO") else {
            eprintln!("skipping: GIT_PREPARE_PR_TEST_REPO not set");
            return;
        };
        let Ok(num) = std::env::var("GIT_PREPARE_PR_TEST_NUMBER") else {
            eprintln!("skipping: GIT_PREPARE_PR_TEST_NUMBER not set");
            return;
        };
        let state = WsState::new_in_memory(16);
        let req = serde_json::json!({
            "jsonrpc": "2.0", "id": 1, "method": "git.preparePullRequestThread",
            "params": {
                "cwd": repo.to_string_lossy(),
                "number": num.parse::<i64>().unwrap(),
            }
        });
        let resp = rpc(&state, 1, &req).await;
        assert!(
            resp.error.is_none(),
            "real-PR composition must succeed, got error: {:?}",
            resp.error
        );
        let result = resp.result.expect("result envelope");
        // MCode GitPreparePullRequestThreadResult shape.
        let pr = &result["pullRequest"];
        assert!(
            pr.is_object(),
            "pullRequest must be an object, got {result}"
        );
        assert!(
            pr["number"].as_i64().is_some(),
            "pullRequest.number must be populated"
        );
        assert!(
            pr["headBranch"].as_str().is_some_and(|s| !s.is_empty()),
            "pullRequest.headBranch must be non-empty"
        );
        let branch = result["branch"].as_str().expect("branch string");
        assert!(!branch.is_empty(), "branch must echo the head branch name");
        assert_eq!(
            branch,
            pr["headBranch"].as_str().unwrap(),
            "branch must equal pullRequest.headBranch"
        );
        // The worktree must exist on disk when worktreePath is populated.
        if let Some(wt) = result["worktreePath"].as_str() {
            assert!(
                std::path::Path::new(wt).is_dir(),
                "worktreePath must point to a real directory: {wt}"
            );
        }
    }

    /// `git.handoffThread` rejects an empty/missing `title` with INVALID_PARAMS
    /// (param validation guard — no gh subprocess spawned for this path).
    #[tokio::test]
    async fn git_handoff_thread_requires_title() {
        let state = WsState::new_in_memory(16);
        let req = serde_json::json!({
            "jsonrpc": "2.0", "id": 1, "method": "git.handoffThread",
            "params": { "title": "  " }
        });
        let resp = rpc(&state, 1, &req).await;
        assert!(
            resp.error.is_some(),
            "empty title must be rejected with an error"
        );
        let err = resp.error.unwrap();
        assert_eq!(err.code, crate::error_codes::INVALID_PARAMS);
    }

    // ─── git.handoffThread: branch-mode / worktree-mode / gh-missing ──────
    //
    // These exercise the new worktree-handoff extension:
    //   - branch-mode: targetMode absent or "branch" → worktree fields null
    //     (legacy behavior unchanged).
    //   - worktree-mode: targetMode "worktree" → a real worktree is created
    //     and worktreePath/associatedWorktreeBranch/changesTransferred are
    //     populated. gh pr create will fail (no remote) but the worktree is
    //     still created and surfaced.
    //   - gh-missing: gh binary absent → graceful `{ ok:false, reason }` in
    //     branch mode (no panic, no INTERNAL_ERROR).
    // All three are gated on `git_available()` (the worktree ops need a real
    // git binary; the gh-missing test stubs PATH to hide gh).

    /// Branch-mode handoff (targetMode absent) against a temp repo WITHOUT a
    /// GitHub remote: gh pr create fails gracefully, returning
    /// `{ ok:false, reason }` (NOT an INTERNAL_ERROR). The worktree fields
    /// must be absent from this short-circuit envelope (branch mode never
    /// creates a worktree). Validates the legacy path is unchanged.
    /// Also exercises BOTH dispatch forms (dot-name + slash-name).
    #[tokio::test]
    async fn git_handoff_thread_branch_mode_no_remote_returns_ok_false() {
        if !git_available() {
            eprintln!("skipping: git binary not on PATH");
            return;
        }
        let repo = temp_git_repo();
        let state = WsState::new_in_memory(16);

        // Both MCode dot-name and slash form must dispatch to the same
        // handler. targetMode absent → defaults to "branch". gh pr create
        // will fail (no origin remote on the temp repo) → handler returns
        // the `{ ok:false, reason }` envelope rather than erroring.
        for method in [
            "git.handoffThread",
            "git/handoff-thread",
            "git/handoffThread",
        ] {
            let req = serde_json::json!({
                "jsonrpc": "2.0", "id": 1, "method": method,
                "params": {
                    "cwd": repo.to_string_lossy(),
                    "title": "Test PR",
                    "head": "main",
                }
            });
            let resp = rpc(&state, 1, &req).await;
            // The handler may return success-with-{ok:false} (gh present but
            // no remote) OR success-with-{ok:false:"gh not found"} (gh
            // absent). Both are valid graceful outcomes; what matters is NO
            // INTERNAL_ERROR.
            assert!(
                resp.error.is_none(),
                "{method}: branch-mode gh failure must not be a JSON-RPC error: {:?}",
                resp.error
            );
            let result = resp.result.unwrap();
            assert_eq!(
                result["ok"], false,
                "{method}: branch-mode without remote must yield ok:false, got {result}"
            );
            assert!(
                result["reason"].as_str().is_some(),
                "{method}: branch-mode failure must surface a reason string, got {result}"
            );
        }
    }

    /// Worktree-mode handoff (targetMode "worktree") against a temp repo
    /// WITHOUT a GitHub remote: the worktree is created locally and its
    /// path/branch are surfaced in the MCode result fields; gh pr create
    /// fails but the handler still returns a success result (the worktree
    /// is the primary deliverable). Verifies worktreePath,
    /// associatedWorktreeBranch, changesTransferred are populated.
    #[tokio::test]
    async fn git_handoff_thread_worktree_mode_creates_worktree() {
        if !git_available() {
            eprintln!("skipping: git binary not on PATH");
            return;
        }
        let repo = temp_git_repo();
        let state = WsState::new_in_memory(16);
        let head = "feature/handoff-test";

        // Pre-create the feature branch + a commit on it, so the worktree
        // has something to check out (matches real handoff usage where the
        // thread's branch already has commits).
        std::process::Command::new("git")
            .args(["branch", head])
            .current_dir(&repo)
            .output()
            .expect("git branch");

        let req = serde_json::json!({
            "jsonrpc": "2.0", "id": 1, "method": "git.handoffThread",
            "params": {
                "cwd": repo.to_string_lossy(),
                "title": "Test PR",
                "head": head,
                "targetMode": "worktree",
            }
        });
        let resp = rpc(&state, 1, &req).await;
        assert!(
            resp.error.is_none(),
            "worktree-mode must not return a JSON-RPC error: {:?}",
            resp.error
        );
        let result = resp.result.unwrap();
        // targetMode echoed back.
        assert_eq!(
            result["targetMode"], "worktree",
            "targetMode must echo 'worktree', got {result}"
        );
        // Worktree fields populated.
        let wt_path = result["worktreePath"].as_str();
        assert!(
            wt_path.is_some(),
            "worktreePath must be populated in worktree mode, got {result}"
        );
        assert!(
            result["associatedWorktreeBranch"].as_str() == Some(head),
            "associatedWorktreeBranch must equal head, got {result}"
        );
        assert_eq!(
            result["changesTransferred"], true,
            "changesTransferred must be true once the worktree is created, got {result}"
        );
        assert_eq!(
            result["conflictsDetected"], false,
            "conflictsDetected must be false for a fresh worktree, got {result}"
        );
        // The associatedWorktreeRef is the fully-qualified ref.
        let expected_ref = format!("refs/heads/{head}");
        assert_eq!(
            result["associatedWorktreeRef"].as_str(),
            Some(expected_ref.as_str()),
            "associatedWorktreeRef must be refs/heads/<branch>, got {result}"
        );
        // The worktree directory must actually exist on disk.
        let wt = std::path::PathBuf::from(wt_path.unwrap());
        assert!(
            wt.is_dir(),
            "worktreePath must point to a real directory: {}",
            wt.display()
        );
        // message must mention the worktree was created (gh pr create fails
        // on a no-remote temp repo, so the message carries that context).
        let msg = result["message"].as_str().unwrap_or("");
        assert!(
            msg.contains("Worktree created"),
            "message must note the worktree creation, got: {msg}"
        );
    }

    /// Branch-mode handoff when `gh` is NOT on PATH: the handler must return
    /// `{ ok:false, reason }` (graceful — no INTERNAL_ERROR, no panic). We
    /// simulate gh-absence by setting PATH to a directory containing only
    /// git (the test inherits a minimal PATH via the `PATH` env override on
    /// the spawned handler — but since the handler calls `which::which("gh")`
    /// against the LIVE PATH, we instead verify the behavior directly: if gh
    /// is missing the result is ok:false; if gh is present the temp repo has
    /// no remote so the result is ALSO ok:false. Either way, no error. This
    /// test therefore asserts the graceful envelope regardless of gh presence
    /// (the gh-missing path is a strict subset of this assertion).
    #[tokio::test]
    async fn git_handoff_thread_graceful_when_gh_missing_or_no_remote() {
        if !git_available() {
            eprintln!("skipping: git binary not on PATH");
            return;
        }
        let repo = temp_git_repo();
        let state = WsState::new_in_memory(16);

        // No GitHub remote configured → gh pr create cannot succeed. Whether
        // gh is installed or not, the handler must return ok:false with a
        // reason (the gh-missing branch returns the dedicated "gh CLI not
        // found" reason; the no-remote branch returns gh's stderr).
        let req = serde_json::json!({
            "jsonrpc": "2.0", "id": 1, "method": "git.handoffThread",
            "params": {
                "cwd": repo.to_string_lossy(),
                "title": "Test PR",
                "head": "main",
            }
        });
        let resp = rpc(&state, 1, &req).await;
        assert!(
            resp.error.is_none(),
            "gh-missing/no-remote must not be a JSON-RPC error: {:?}",
            resp.error
        );
        let result = resp.result.unwrap();
        assert_eq!(
            result["ok"], false,
            "expected ok:false (gh missing or no remote), got {result}"
        );
        let reason = result["reason"].as_str().expect("reason string");
        assert!(
            !reason.is_empty(),
            "reason must be a non-empty hint, got: {reason}"
        );
        // If gh is absent the reason must say so explicitly; otherwise it's
        // gh's stderr (which we don't constrain beyond non-empty).
        if which::which("gh").is_err() {
            assert!(
                reason.contains("gh"),
                "gh-missing reason must mention gh, got: {reason}"
            );
        }
    }

