    #[tokio::test]
    async fn emit_welcome_on_connect_pushes_server_welcome_payload_directly() {
        // PR-fix-welcome: on connection-accept, the server must push the
        // welcome payload on the `server.welcome` channel (literally). The
        // frontend's `onServerWelcome` listener binds to this exact channel
        // name (see `frontend/src/contracts/tier3/ws.ts::WS_CHANNELS.
        // serverWelcome === "server.welcome"`) and reads `payload.homeDir`
        // directly off `message.data` (= `notification.params`). Without
        // this push the splash screen never resolves because
        // `workspaceStore.homeDir` stays null.
        //
        // Two correctness invariants checked here:
        //   1. The wire `method` is `push/server.welcome` (not
        //      `push/server.lifecycle` — the lifecycle channel is a
        //      separate opt-in stream).
        //   2. The welcome payload sits at the TOP LEVEL of `params` (not
        //      nested inside `{eventType, aggregateId, data}`), because
        //      `WsWelcomePayload` has `homeDir` / `cwd` / `projectName`
        //      as required top-level fields.
        let state = WsState::new_in_memory(16);
        let (tx, mut rx) = tokio::sync::mpsc::unbounded_channel::<String>();
        // Keep a clone for the emit — `register` moves the original.
        let emit_tx = tx.clone();
        state.register(1, tx).await;

        let emitted = emit_welcome_on_connect(&emit_tx, &state);
        assert!(emitted, "welcome push should be delivered to the tx");

        let msg = rx
            .recv()
            .await
            .expect("welcome push should arrive on the connection rx");
        let parsed: serde_json::Value =
            serde_json::from_str(&msg).expect("welcome push is valid JSON");
        assert_eq!(
            parsed["method"], "push/server.welcome",
            "wire method must be push/server.welcome (got: {parsed})"
        );
        // Welcome payload fields at the top level of params — not nested.
        assert!(
            parsed["params"]["homeDir"].is_string(),
            "params.homeDir must be a string (got: {parsed})"
        );
        assert!(
            parsed["params"]["cwd"].is_string(),
            "params.cwd must be a string"
        );
        assert!(
            parsed["params"]["projectName"].is_string(),
            "params.projectName must be a string"
        );
        // Defensive: no `eventType`/`aggregateId` envelope wrapping — the
        // frontend reads `payload.homeDir` directly off `message.data`.
        assert!(
            parsed["params"].get("eventType").is_none(),
            "params must NOT be wrapped in an eventType envelope"
        );
    }

    #[tokio::test]
    async fn emit_welcome_on_connect_returns_false_when_tx_closed() {
        // PR-fix-welcome: a dropped receiver (closed connection) surfaces as
        // `false` so the caller can log without crashing. Best-effort push
        // semantics — never block on a stuck consumer.
        let state = WsState::new_in_memory(16);
        let (tx, rx) = tokio::sync::mpsc::unbounded_channel::<String>();
        drop(rx); // close the receiver
        let emitted = emit_welcome_on_connect(&tx, &state);
        assert!(!emitted, "closed tx should report not-emitted");
    }

    #[tokio::test]
    async fn subscribe_lifecycle_emits_welcome_and_registers_channel() {
        // T6c-phase-27: subscribeLifecycle registers the connection on
        // `server.lifecycle` and pushes an initial `welcome` event on push_tx
        // (observable via a broadcast subscriber). The welcome payload must
        // mirror server.welcome (cwd, projectName, serverVersion, authRequired,
        // mode). Mirrors the subscribe_config snapshot-then-stream test.
        let state = std::sync::Arc::new(WsState::new_in_memory(16));
        let (tx, mut rx) = tokio::sync::mpsc::unbounded_channel::<String>();
        state.register(1, tx.clone()).await;
        // Spawn the delivery loop so the broadcast on push_tx forwards onto
        // the connection's mpsc tx (mirrors the production server.rs handler).
        let _delivery = tokio::spawn(crate::server::run_push_delivery(
            std::sync::Arc::clone(&state),
            1,
            tx,
        ));
        tokio::time::sleep(std::time::Duration::from_millis(50)).await;

        // Independent broadcast subscriber — observes the welcome push even
        // if the per-connection delivery path races.
        let mut bcast_rx = state.push_tx.subscribe();

        let resp = rpc_success(&state, "server.subscribeLifecycle", serde_json::json!({})).await;
        assert!(resp.error.is_none(), "{:?}", resp.error);
        let result = resp.result.unwrap();
        assert_eq!(result["subscribed"], true);
        assert_eq!(result["channel"], crate::channels::CHANNEL_SERVER_LIFECYCLE);
        assert_eq!(result["snapshotEmitted"], true);
        // The response includes the welcome payload so callers can use either
        // server.welcome or server.subscribeLifecycle for bootstrap.
        assert!(result["welcome"]["cwd"].is_string());
        assert!(result["welcome"]["projectName"].is_string());
        assert!(result["welcome"]["serverVersion"].is_string());
        assert!(result["welcome"]["authRequired"].is_boolean());
        assert!(result["welcome"]["mode"].is_string());

        // The broadcast bus carries the welcome event on the lifecycle channel.
        let (channel, data) =
            tokio::time::timeout(std::time::Duration::from_millis(500), bcast_rx.recv())
                .await
                .expect("lifecycle welcome push should arrive on push_tx")
                .unwrap();
        assert_eq!(channel, crate::channels::CHANNEL_SERVER_LIFECYCLE);
        assert_eq!(data["eventType"], "welcome");
        // The welcome payload data mirrors server.welcome.
        assert!(data["data"]["cwd"].is_string());
        assert!(data["data"]["projectName"].is_string());
        assert!(data["data"]["serverVersion"].is_string());

        // The forwarded per-connection frame arrives too (delivered by
        // run_push_delivery). It should be a `push/server.lifecycle` message
        // with `eventType: "welcome"`.
        let msg = tokio::time::timeout(std::time::Duration::from_millis(500), rx.recv())
            .await
            .expect("welcome push should arrive on connection tx")
            .unwrap();
        assert!(msg.contains("push/server.lifecycle"));
        assert!(msg.contains("welcome"));

        // The subscription is recorded — conn 1 is now on the lifecycle channel.
        let subscribers = state
            .subscriptions
            .read()
            .await
            .subscribers_for(crate::channels::CHANNEL_SERVER_LIFECYCLE);
        assert!(
            subscribers.contains(&1),
            "conn 1 should be subscribed to server.lifecycle (got {:?})",
            subscribers
        );
    }

    /// Helper: subscribe conn 1 to lifecycle, drain the initial `welcome`
    /// broadcast, then return a fresh broadcast receiver that observes only
    /// subsequent lifecycle events. Mirrors the snapshot-then-stream seam the
    /// delivery loop reads from. `bcast_rx` is created AFTER subscribe returns
    /// so it does NOT see the welcome (only the events triggered after it).
    async fn lifecycle_sub_after_welcome(
        state: &WsState,
    ) -> tokio::sync::broadcast::Receiver<(String, serde_json::Value)> {
        let resp = rpc_success(state, "server.subscribeLifecycle", serde_json::json!({})).await;
        assert!(resp.error.is_none(), "{:?}", resp.error);
        // Fresh receiver: only sees events sent after this point (the welcome
        // was already sent inside subscribeLifecycle and is skipped).
        state.push_tx.subscribe()
    }

    /// Helper: drain `bcast_rx` until a `server.lifecycle` broadcast arrives
    /// (or timeout). Some write handlers (setConfig/updateSettings/
    /// refreshProviders) emit TWO broadcasts — the dedicated `server.*Updated`
    /// channel first, then the lifecycle mirror — so we must skip the
    /// non-lifecycle frames to assert on the lifecycle payload.
    async fn next_lifecycle_event(
        bcast_rx: &mut tokio::sync::broadcast::Receiver<(String, serde_json::Value)>,
    ) -> (String, serde_json::Value) {
        let deadline = std::time::Duration::from_millis(500);
        loop {
            let (channel, data) = tokio::time::timeout(deadline, bcast_rx.recv())
                .await
                .expect("a lifecycle event should arrive on push_tx")
                .expect("broadcast channel not closed");
            if channel == crate::channels::CHANNEL_SERVER_LIFECYCLE {
                return (channel, data);
            }
            // Skip non-lifecycle broadcasts (e.g. server.configUpdated emitted
            // just before the lifecycle mirror in the same handler).
        }
    }

    #[tokio::test]
    async fn subscribe_lifecycle_receives_local_server_started_event() {
        // SRV-3: after subscribing to lifecycle, a `startLocalServer` write
        // must broadcast a `local-server-started` event on the lifecycle
        // channel (so subscribers learn a local server came up).
        let state = WsState::new_in_memory(16);
        let mut bcast_rx = lifecycle_sub_after_welcome(&state).await;

        let resp = rpc(
            &state,
            1,
            &serde_json::json!({
                "jsonrpc": "2.0", "id": 2, "method": "server.startLocalServer",
                "params": {
                    "id": "lifecycle-started",
                    "name": "sleeper",
                    "command": "sleep",
                    "args": ["30"],
                }
            }),
        )
        .await;
        assert!(resp.error.is_none(), "{:?}", resp.error);
        let started_id = resp.result.unwrap()["id"].as_str().unwrap().to_string();

        let (channel, data) = next_lifecycle_event(&mut bcast_rx).await;
        assert_eq!(channel, crate::channels::CHANNEL_SERVER_LIFECYCLE);
        assert_eq!(data["eventType"], "local-server-started");
        assert_eq!(data["aggregateId"], started_id);
        assert_eq!(data["data"]["command"], "sleep");

        // Cleanup: stop the spawned process.
        let _ = rpc(
            &state,
            1,
            &serde_json::json!({
                "jsonrpc": "2.0", "id": 3, "method": "server.stopLocalServer",
                "params": { "id": "lifecycle-started" }
            }),
        )
        .await;
    }

    #[tokio::test]
    async fn subscribe_lifecycle_receives_local_server_stopped_event() {
        // SRV-3: a `stopLocalServer` write must broadcast a
        // `local-server-stopped` event on the lifecycle channel.
        let state = WsState::new_in_memory(16);

        // Start a server BEFORE subscribing so the `started` event doesn't
        // pollute the lifecycle receiver.
        let start_resp = rpc(
            &state,
            1,
            &serde_json::json!({
                "jsonrpc": "2.0", "id": 2, "method": "server.startLocalServer",
                "params": {
                    "id": "lifecycle-stopped",
                    "name": "sleeper",
                    "command": "sleep",
                    "args": ["30"],
                }
            }),
        )
        .await;
        assert!(start_resp.error.is_none(), "{:?}", start_resp.error);

        let mut bcast_rx = lifecycle_sub_after_welcome(&state).await;

        let resp = rpc(
            &state,
            1,
            &serde_json::json!({
                "jsonrpc": "2.0", "id": 3, "method": "server.stopLocalServer",
                "params": { "id": "lifecycle-stopped" }
            }),
        )
        .await;
        assert!(resp.error.is_none(), "{:?}", resp.error);

        let (channel, data) = next_lifecycle_event(&mut bcast_rx).await;
        assert_eq!(channel, crate::channels::CHANNEL_SERVER_LIFECYCLE);
        assert_eq!(data["eventType"], "local-server-stopped");
        assert_eq!(data["aggregateId"], "lifecycle-stopped");
    }

